import{_ as a}from"./plugin-vue_export-helper-c27b6911.js";import{o as i,c as e,f as c}from"./app-7cfa41e7.js";const n={},r=c('<h2 id="同步调用" tabindex="-1"><a class="header-anchor" href="#同步调用" aria-hidden="true">#</a> 同步调用</h2><h2 id="异步调用" tabindex="-1"><a class="header-anchor" href="#异步调用" aria-hidden="true">#</a> 异步调用</h2><p>优势:</p><ul><li>解除耦合,拓展性强</li><li>无需等待，性能好</li><li>故障隔离</li><li>缓存消息,流量削封填故<img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697113469379-0c7ff936-ecc6-4b33-b762-eb42be45962c.png" alt="img" loading="lazy"></li></ul><p>缺点</p><ul><li>时效性低,拿不到结果</li><li>不确定执行是否成功</li><li>业务安全依靠Broker</li></ul><h2 id="技术选型" tabindex="-1"><a class="header-anchor" href="#技术选型" aria-hidden="true">#</a> 技术选型</h2><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697113469349-39487efd-6d6e-42b2-b0d9-c475a6a72c61.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="认识和安装" tabindex="-1"><a class="header-anchor" href="#认识和安装" aria-hidden="true">#</a> 认识和安装</h2><h3 id="rbmq整体架构概念" tabindex="-1"><a class="header-anchor" href="#rbmq整体架构概念" aria-hidden="true">#</a> RBMQ整体架构概念：</h3><ul><li>virtual-host:虚拟主机,起到数据隔离的作用</li><li>publiser:消息发送者</li><li>consumer:消息的消费者</li><li>queue:队列,存储消息</li><li>exchange:交换机,负责路由消息</li></ul><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697113469466-edb5a315-3d19-4b9b-beb8-abaffb2b5161.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="快速入门" tabindex="-1"><a class="header-anchor" href="#快速入门" aria-hidden="true">#</a> 快速入门</h2><p>建队列,交换机绑定队列,然后路由发送到队列(队列都收到了)</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697294649765-3017567d-b976-4dbf-89d1-190bb2ad84e4.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="数据隔离" tabindex="-1"><a class="header-anchor" href="#数据隔离" aria-hidden="true">#</a> 数据隔离</h2><h2 id="amqp" tabindex="-1"><a class="header-anchor" href="#amqp" aria-hidden="true">#</a> AMQP</h2><p>翻译过来就是高级消息队列协议</p><p>Spring AMQP</p><p>spring-rabbit是底层默认实现</p><h2 id="work模型" tabindex="-1"><a class="header-anchor" href="#work模型" aria-hidden="true">#</a> Work模型</h2><ul><li>多个消费者绑定到一个队列,可以加快消息处理的速度</li><li>同一条消息只会被一个消费者处理</li><li>通过设置prefetch来控制消费者预取的消息数量,处理完一条再处理吓一跳,实现能者多劳</li></ul><h2 id="fanout交换机" tabindex="-1"><a class="header-anchor" href="#fanout交换机" aria-hidden="true">#</a> Fanout交换机</h2><p>真实生产环境都会警告exchange来发送消息,而不是直接发送到队列,交换机的类型有三种</p><ul><li>Fanout:广播</li><li>Direct:定向</li><li>Topic:话题</li></ul><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697119963073-59b92807-84f7-4356-b895-101f040577f8.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>Fanout Exchange会将接收到的消息广播到每一个跟其绑定的Queue，所以叫广播模式</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697120012272-be575474-866b-4db4-85bb-cea4b685498a.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="direct交换机" tabindex="-1"><a class="header-anchor" href="#direct交换机" aria-hidden="true">#</a> Direct交换机</h2><ul><li>每一个Queue都与Exchange设置一个BindingKey</li><li>发布者发送消息时,指定消息的RoutingKey</li><li>Exchange将消息路由到BindingKey与消息RoutingKey一致的队列</li></ul><h2 id="topic交换机" tabindex="-1"><a class="header-anchor" href="#topic交换机" aria-hidden="true">#</a> Topic交换机</h2><p>TopicExchange与DirectExchange类似,区别在于routingKey可以是多个单词的列表,并且以**.**分割</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697121868499-4c563246-1b4e-4505-9836-4a4665b558fe.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="生产者重连" tabindex="-1"><a class="header-anchor" href="#生产者重连" aria-hidden="true">#</a> 生产者重连</h2><h2 id="生产者确认" tabindex="-1"><a class="header-anchor" href="#生产者确认" aria-hidden="true">#</a> 生产者确认</h2><h2 id="数据持久化" tabindex="-1"><a class="header-anchor" href="#数据持久化" aria-hidden="true">#</a> 数据持久化</h2><p>一般就是消息的持久化</p><h2 id="lazy-queue" tabindex="-1"><a class="header-anchor" href="#lazy-queue" aria-hidden="true">#</a> Lazy Queue</h2><p>惰性队列</p><ul><li>接收到消息后直接存入磁盘而非内存(内存中只保留最近的消息,默认2048条)</li><li>消费者要消费消息才会从磁盘中读取并加载到内存</li><li>支持数百万条的存储</li><li>在3.12版本后,所有队列都是lazy queue模式,无法更改</li></ul><h2 id="消费者确认机制" tabindex="-1"><a class="header-anchor" href="#消费者确认机制" aria-hidden="true">#</a> 消费者确认机制</h2><ul><li>ack:成功处理消息,RabbitMQ从队列中删除该消息</li><li>nack:消息处理失败，RabbitMQ需要再次投递消息</li><li>reject:消息处理失败并拒绝该消息,RabbitMQ从队列中删除该消息</li></ul><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697270260339-3c3ca8c8-0a46-47ec-8f62-37382f016bda.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="消费者失败处理" tabindex="-1"><a class="header-anchor" href="#消费者失败处理" aria-hidden="true">#</a> 消费者失败处理</h2><p>开启重试模式后,重试次数耗尽,如果消息依然失败,需要有MessageRecover接口来处理,包含三种不同的实现:</p><ul><li>RejectAndDontRequeueRecover：重试耗尽后,直接reject,丢弃消息。默认这种方式</li><li>ImmediateRequeueMessageRecoverer:重试耗尽后,返回nack,消息重新入队</li><li>RepublishMessageRecoverer:重试耗尽后,将失败消息投递到指定交换机</li></ul><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697269720637-b4c67ba4-aa84-4875-b584-82d4cef38216.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="业务幂等性" tabindex="-1"><a class="header-anchor" href="#业务幂等性" aria-hidden="true">#</a> 业务幂等性</h2><figure><img src="https://cdn.nlark.com/yuque/0/2023/png/22577838/1697270381592-d0412177-878f-47aa-85d8-6eebba18af8a.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p><strong>面试也会经常问到,如何保持业务幂等性。</strong></p><p>第一种是加上唯一ID</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697271043240-eb643a6c-6691-4276-ac06-f76451d72256.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>如何保证支付服务与交易服务之间的订单状态一致性</p><figure><img src="https://cdn.nlark.com/yuque/0/2023/png/22577838/1697271512679-6999cf0b-11e6-4f4a-a184-8086f1789102.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><p>如果交易服务消息处理失败,有没有什么失败兜底方案</p><figure><img src="https://cdn.nlark.com/yuque/0/2023/png/22577838/1697271589387-20685ec7-8a2e-48b9-a167-ef7e01a61ff3.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="延时消息" tabindex="-1"><a class="header-anchor" href="#延时消息" aria-hidden="true">#</a> 延时消息</h2><p>延时消息：生产者发送消息指定一个时间,消费者不会立刻收到消息,而是在指定时间后才收到消息</p><p>延时任务:设置一定时间之后才执行的任务</p><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697283208880-6e05a6ec-2ce4-44bb-bb4d-91fab1e9ca19.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><h2 id="死信交换机" tabindex="-1"><a class="header-anchor" href="#死信交换机" aria-hidden="true">#</a> 死信交换机</h2><figure><img src="https://cdn.nlark.com/yuque/0/2023/png/22577838/1697283347376-65d78979-905e-4753-8ce1-beaf90cb25a9.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure><figure><img src="https://skyme-1307417630.cos.ap-chengdu.myqcloud.com/skyme/1697284948316-0a004e87-eb17-44ac-8866-8a092fdd27c3.png" alt="img" tabindex="0" loading="lazy"><figcaption>img</figcaption></figure>',63),d=[r];function t(l,g){return i(),e("div",null,d)}const s=a(n,[["render",t],["__file","rabbitmq.html.vue"]]);export{s as default};
